task.mock_day2_solution:
from __future__ import annotations


def parse_csv_rows(lines, normalize_header=None):
    header = None
    for raw in lines:
        text = raw.strip()
        if not text:
            continue
        if header is None:
            names = [part.strip() for part in text.split(',')]
            if normalize_header is not None:
                names = [normalize_header(name) for name in names]
            header = names
            continue
        values = [part.strip() for part in text.split(',')]
        yield {header[index]: values[index] for index in range(min(len(header), len(values)))}

