def test_parses_rows_lazily():
    consumed = []

    def lines():
        for line in ['name,age', 'Ada,36', 'Grace,40']:
            consumed.append(line)
            yield line

    rows = parse_csv_rows(lines())
    assert next(rows) == {'name': 'Ada', 'age': '36'}
